// app/dashboard/users/page.tsx - Debug version
'use client'

import { useState, useEffect } from 'react'
import { Header } from '../../../components/layout/Header'
import { SearchBar } from '../../../components/common/SearchBar'
import { Pagination } from '../../../components/common/Pagination'
import { FiDownload, FiRefreshCw, FiUsers, FiActivity, FiShield, FiAlertCircle } from 'react-icons/fi'
import { supabase } from '../../../lib/supabase'
import { toast } from 'react-hot-toast'
import { User } from '../../../types'

export default function UsersPage() {
  const [users, setUsers] = useState<User[]>([])
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState<string | null>(null)
  const [search, setSearch] = useState('')
  const [page, setPage] = useState(1)
  const [filter, setFilter] = useState('all')
  const itemsPerPage = 10
  const [debugData, setDebugData] = useState<any>(null)

  // Fetch users directly from the database
  const fetchUsers = async () => {
    try {
      setLoading(true)
      setError(null)
      
      console.log('=== STARTING USER FETCH ===')
      
      // Fetch all users from users table
      console.log('Fetching from users table...')
      const { data: usersData, error: usersError, count } = await supabase
        .from('users')
        .select('*', { count: 'exact' })
        .order('created_at', { ascending: false })

      console.log('Users fetch result:', {
        dataLength: usersData?.length,
        error: usersError,
        count: count
      })

      if (usersError) {
        console.error('Error fetching users:', usersError)
        
        if (usersError.code === 'PGRST116') {
          setError('Users table does not exist. Please run database setup.')
          toast.error('Database tables not set up. Please run setup.')
          return
        }
        
        throw usersError
      }

      console.log(`Found ${usersData?.length || 0} users in database`)
      console.log('First 3 users:', usersData?.slice(0, 3))

      if (!usersData || usersData.length === 0) {
        console.log('No users found in database')
        setUsers([])
        return
      }

      // Get user IDs to fetch their profiles
      const userIds = usersData.map(user => user.id)
      console.log('User IDs:', userIds)
      
      // Fetch profiles for these users
      console.log('Fetching profiles...')
      const { data: profilesData, error: profilesError } = await supabase
        .from('profiles')
        .select('*')
        .in('id', userIds)

      console.log('Profiles fetch result:', {
        dataLength: profilesData?.length,
        error: profilesError
      })

      // Create a map of profiles by user ID
      const profilesMap = new Map()
      profilesData?.forEach(profile => {
        profilesMap.set(profile.id, profile)
      })
      console.log('Profiles map size:', profilesMap.size)

      // Combine users with their profiles
      const combinedUsers = usersData.map(user => ({
        ...user,
        profile: profilesMap.get(user.id) || null,
        search_history: [],
        location_history: []
      }))

      console.log('Combined users count:', combinedUsers.length)
      console.log('First combined user:', combinedUsers[0])
      
      // Save debug data
      setDebugData({
        usersCount: usersData.length,
        profilesCount: profilesData?.length || 0,
        combinedCount: combinedUsers.length,
        sampleUser: combinedUsers[0]
      })
      
      setUsers(combinedUsers)
      
      console.log('=== USER FETCH COMPLETE ===')
      
    } catch (err: any) {
      console.error('Failed to fetch users:', err)
      setError(err.message || 'Unknown error occurred')
      toast.error('Failed to load users')
    } finally {
      setLoading(false)
    }
  }

  // Fetch users on component mount
  useEffect(() => {
    fetchUsers()
  }, [])

  // Filter and search users
  const filteredUsers = users.filter(user => {
    // Search filter
    if (search) {
      const searchLower = search.toLowerCase()
      const firstName = (user.first_name || '').toLowerCase()
      const lastName = (user.last_name || '').toLowerCase()
      const email = (user.email || '').toLowerCase()
      
      const matchesSearch = 
        firstName.includes(searchLower) ||
        lastName.includes(searchLower) ||
        email.includes(searchLower)
      
      if (!matchesSearch) return false
    }

    // Role filter
    if (filter === 'banned' && user.profile?.role !== 'banned') return false
    if (filter === 'active' && user.profile?.role !== 'user') return false
    if (filter === 'admin' && user.profile?.role !== 'admin') return false

    return true
  })

  // Pagination
  const totalPages = Math.max(1, Math.ceil(filteredUsers.length / itemsPerPage))
  const paginatedUsers = filteredUsers.slice(
    (page - 1) * itemsPerPage,
    page * itemsPerPage
  )

  // Simple table component for debugging
  const SimpleUsersTable = () => {
    if (loading) {
      return (
        <div className="text-center py-12">
          <div className="inline-block animate-spin rounded-full h-8 w-8 border-b-2 border-primary"></div>
          <p className="mt-4 text-text">Loading users from database...</p>
        </div>
      )
    }

    if (users.length === 0) {
      return (
        <div className="text-center py-12">
          <p className="text-text-light">No users found in database</p>
        </div>
      )
    }

    return (
      <div className="overflow-x-auto">
        <table className="min-w-full divide-y divide-gray-200">
          <thead>
            <tr>
              <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">ID</th>
              <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Name</th>
              <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Email</th>
              <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Role</th>
              <th className="px-6 py-3 text-left text-xs font-medium text-gray-500 uppercase tracking-wider">Created</th>
            </tr>
          </thead>
          <tbody className="bg-white divide-y divide-gray-200">
            {paginatedUsers.map((user) => (
              <tr key={user.id}>
                <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                  {user.id.substring(0, 8)}...
                </td>
                <td className="px-6 py-4 whitespace-nowrap">
                  <div className="text-sm font-medium text-gray-900">
                    {user.first_name} {user.last_name}
                  </div>
                </td>
                <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                  {user.email}
                </td>
                <td className="px-6 py-4 whitespace-nowrap">
                  <span className={`px-2 inline-flex text-xs leading-5 font-semibold rounded-full ${
                    user.profile?.role === 'admin' 
                      ? 'bg-purple-100 text-purple-800'
                      : user.profile?.role === 'banned'
                      ? 'bg-red-100 text-red-800'
                      : 'bg-green-100 text-green-800'
                  }`}>
                    {user.profile?.role || 'user'}
                  </span>
                </td>
                <td className="px-6 py-4 whitespace-nowrap text-sm text-gray-900">
                  {new Date(user.created_at).toLocaleDateString()}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
    )
  }

  const userStats = {
    total: users.length,
    active: users.filter(u => u.profile?.role === 'user').length,
    banned: users.filter(u => u.profile?.role === 'banned').length,
    admin: users.filter(u => u.profile?.role === 'admin').length,
    todayActive: users.filter(u => {
      const lastSeen = new Date(u.profile?.last_seen_at || u.updated_at)
      const today = new Date()
      return lastSeen.toDateString() === today.toDateString()
    }).length
  }

  return (
    <div className="space-y-6">
      <Header 
        title="User Management" 
        subtitle="Manage all user accounts from the database"
      />

      {/* Debug Info (only show in development) */}
      {process.env.NODE_ENV === 'development' && debugData && (
        <div className="bg-yellow-50 border border-yellow-200 rounded-lg p-4">
          <h3 className="font-semibold text-yellow-800 mb-2">Debug Info:</h3>
          <pre className="text-xs overflow-x-auto">
            {JSON.stringify(debugData, null, 2)}
          </pre>
        </div>
      )}

      {/* Stats Overview */}
      <div className="grid grid-cols-1 md:grid-cols-4 gap-6">
        <div className="bg-white rounded-lg shadow p-6">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-text-light text-sm">Total Users</p>
              <p className="text-3xl font-bold text-text mt-2">{userStats.total}</p>
            </div>
            <FiUsers className="text-4xl text-blue-100" />
          </div>
          <div className="mt-2 text-xs text-gray-500">
            Database count: {users.length}
          </div>
        </div>
        
        <div className="bg-white rounded-lg shadow p-6">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-text-light text-sm">Active Today</p>
              <p className="text-3xl font-bold text-green-600 mt-2">{userStats.todayActive}</p>
            </div>
            <FiActivity className="text-4xl text-green-100" />
          </div>
        </div>
        
        <div className="bg-white rounded-lg shadow p-6">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-text-light text-sm">Banned Users</p>
              <p className="text-3xl font-bold text-red-600 mt-2">{userStats.banned}</p>
            </div>
            <FiAlertCircle className="text-4xl text-red-100" />
          </div>
        </div>
        
        <div className="bg-white rounded-lg shadow p-6">
          <div className="flex items-center justify-between">
            <div>
              <p className="text-text-light text-sm">Admins</p>
              <p className="text-3xl font-bold text-purple-600 mt-2">{userStats.admin}</p>
            </div>
            <FiShield className="text-4xl text-purple-100" />
          </div>
        </div>
      </div>

      <div className="bg-white rounded-lg shadow p-6">
        <div className="flex items-center justify-between mb-6">
          <div className="flex items-center space-x-4">
            <SearchBar 
              value={search}
              onChange={setSearch}
              placeholder="Search users by name or email..."
            />
            
            <select
              value={filter}
              onChange={(e) => {
                setFilter(e.target.value)
                setPage(1)
              }}
              className="px-4 py-2 border border-gray-300 rounded-lg focus:outline-none focus:ring-2 focus:ring-primary focus:border-transparent"
            >
              <option value="all">All Users</option>
              <option value="active">Active Users</option>
              <option value="admin">Admins</option>
              <option value="banned">Banned Users</option>
            </select>
          </div>

          <div className="flex items-center space-x-3">
            <button
              onClick={fetchUsers}
              disabled={loading}
              className="flex items-center space-x-2 px-4 py-2 border border-gray-300 rounded-lg hover:bg-gray-50 disabled:opacity-50"
            >
              <FiRefreshCw className={loading ? 'animate-spin' : ''} />
              <span>Refresh</span>
            </button>
            <button
              onClick={() => {
                console.log('Current users state:', users)
                console.log('Filtered users:', filteredUsers)
                console.log('Paginated users:', paginatedUsers)
                alert('Check browser console for user data')
              }}
              className="flex items-center space-x-2 px-4 py-2 border border-gray-300 rounded-lg hover:bg-gray-50"
            >
              <FiAlertCircle />
              <span>Debug</span>
            </button>
          </div>
        </div>

        {error && !loading && (
          <div className="mb-6 p-4 bg-red-50 border border-red-200 rounded-lg">
            <div className="flex items-center">
              <FiAlertCircle className="text-red-500 mr-3" />
              <div>
                <p className="font-medium text-red-800">Error loading users</p>
                <p className="text-red-700 text-sm mt-1">{error}</p>
                <button
                  onClick={fetchUsers}
                  className="mt-2 px-3 py-1 bg-red-100 text-red-700 rounded text-sm hover:bg-red-200"
                >
                  Retry
                </button>
              </div>
            </div>
          </div>
        )}

        <SimpleUsersTable />

        {filteredUsers.length > 0 && (
          <div className="mt-6">
            <Pagination 
              currentPage={page}
              totalPages={totalPages}
              onPageChange={setPage}
            />
            <div className="mt-4 text-sm text-text-light text-center">
              Showing {paginatedUsers.length} of {filteredUsers.length} users
              {filter !== 'all' && ` (filtered by: ${filter})`}
            </div>
          </div>
        )}
      </div>
    </div>
  )
}